/// Filter result for a scheduled transaction
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum FilterResult {
    /// Transaction is valid and should be included
    Valid,
    /// C1: Call not found in Scheduler contract
    C1CallNotFound,
    /// C2: Call state is not SCHEDULED (cancelled, completed, expired)
    C2InvalidState,
    /// C3: Execution index >= numCalls
    C3IndexOutOfBounds,
    /// C4: Block number < expected block (too early)
    C4TooEarly,
    /// C5: Block number > expected block + TTL (too late for this execution)
    C5TooLate,
    /// C6: Block number > overall expiry (call is completely expired)
    C6Expired,
    /// C7: Invalid signature (not the expected dummy signature)
    C7InvalidSignature,
    /// C8: Target address is not the Scheduler contract
    C8InvalidTarget,

}

#[test]
fn test_compute_max_block_number_helpers_match_expiry_logic() {
    assert_eq!(compute_max_block_number_u64(100, 5, 10, 10), 155);
    assert_eq!(compute_max_block_number_u32_saturating(100, 5, 10, 10), 155);

    // Zero-call schedules have no valid execution window.
    assert_eq!(compute_max_block_number_u64(100, 5, 0, 10), 0);
    assert_eq!(compute_max_block_number_u32_saturating(100, 5, 0, 10), 0);

    // Saturates to u32::MAX for u32 consumers while preserving full u64 value.
    let u64_max = compute_max_block_number_u64(u32::MAX, u32::MAX, u32::MAX, u32::MAX);
    assert!(u64_max > u32::MAX as u64);
    assert_eq!(
        compute_max_block_number_u32_saturating(u32::MAX, u32::MAX, u32::MAX, u32::MAX),
        u32::MAX
    );
}

